SELECT l.id AS logId, l.admin_user_id AS adminUserId, a.nickname AS adminNickname, l.module_name AS moduleName, l.action_name AS actionName, l.target_type AS targetType, l.target_id AS targetId, l.request_ip AS requestIp, l.content_json AS contentJson, l.created_at AS createdAt FROM sys_operation_log l LEFT JOIN sys_admin_user a ON a.id = l.admin_user_id
AND l.admin_user_id = #{adminUserId}
AND l.module_name = #{moduleName}
ORDER BY l.created_at DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM sys_operation_log


        AND admin_user_id = #{adminUserId}


        AND module_name = #{moduleName}
